298:     private fun parseToolCall(response: String): Pair<String, String>? {
299:         val actionLine = response.lines().firstOrNull { it.trimStart().startsWith("ACTION:") }
300:         if (actionLine != null) {
301:             val content = actionLine.trimStart().removePrefix("ACTION:").trim()
302:             val pipeIdx = content.indexOf('|')
303:             return if (pipeIdx >= 0) {
304:                 Pair(content.substring(0, pipeIdx).trim(), content.substring(pipeIdx + 1).trim())
305:             } else {
306:                 Pair(content.trim(), "")
307:             }
308:         }
309: 
310:         // Fallback: old JSON format
311:         val jsonMatch = Regex("""\{[^}]+\}""").find(response) ?: return null
312:         return try {
313:             val json = jsonMatch.value
314:             val name = Regex(""""tool_name"\s*:\s*"(\w+)"""").find(json)?.groupValues?.get(1)
315:             val args = Regex(""""arguments"\s*:\s*(\{[^}]+\})""").find(json)?.groupValues?.get(1)
316:             if (name != null && args != null) Pair(name, args) else null
317:         } catch (e: Exception) {
318:             null
319:         }
320:     }
